def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def solve_with_checks(nums, target):
    if not nums:
        return -1, -1  # Handle no-solution case
    if len(nums) < 2:
        return -1, -1  # Not enough elements to form a pair

    seen_indices = set()
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            if left in seen_indices or right in seen_indices:
                return -1, -1  # Ensure indices not reused
            seen_indices.add(left)
            seen_indices.add(right)
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1
